async multiForbidden(uids: number[]): Promise<void> {
  if (uids) {
    const pvs: string[] = []
    const ts: string[] = []
    const ps: string[] = []
    uids.forEach((uid) => {
      pvs.push(genAuthPVKey(uid))
      ts.push(genAuthTokenKey(uid))
      ps.push(genAuthPermKey(uid))
    })
    await this.redis.del(pvs)
    await this.redis.del(ts)
    await this.redis.del(ps)
  }
}

