export function getSize(bytes: number, decimals = 2) {
  if (bytes === 0)
    return '0 Bytes'

  const k = 1024
  const dm = decimals < 0 ? 0 : decimals
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB', 'ZB', 'YB']

  const i = Math.floor(Math.log(bytes) / Math.log(k))

  return `${Number.parseFloat((bytes / k ** i).toFixed(dm))} ${sizes[i]}`
}

hashString = function (str, seed = 0) {
  let h1 = 0xDEADBEEF ^ seed
  let h2 = 0x41C6CE57 ^ seed
  for (let i = 0, ch; i < str.length; i++) {
    ch = str.charCodeAt(i)
    h1 = Math.imul(h1 ^ ch, 2654435761)
    h2 = Math.imul(h2 ^ ch, 1597334677)
  }
  h1
    = Math.imul(h1 ^ (h1 >>> 16), 2246822507)
    ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909)
  h2
    = Math.imul(h2 ^ (h2 >>> 16), 2246822507)
    ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909)
  return 4294967296 * (2097151 & h2) + (h1 >>> 0)
}

public exchangeKeyForValue(type: number, data: ParamData, args: any[]) {
  if (!args) {
    return null;
  }

  let index = 0;
  if (type === RABBIT_PARAM_TYPE) {
    index = 0;
  } else if (type === RABBIT_REQUEST_TYPE) {
    index = 1;
  } else if (type === RABBIT_HEADER_TYPE) {
    index = 2;
  }

  return data && !isObject(data) ? args[index]?.[data] : args[index];
}

resolveType(auth) {
  if (auth.type === WebhookAuthEnum.API_KEY) {
    return AuthApiKey;
  }
  if (auth.type === WebhookAuthEnum.BASIC) {
    return AuthBasic;
  }
  if (auth.type === WebhookAuthEnum.TOKEN) {
    return AuthToken;
  }
  if (auth.type === WebhookAuthEnum.OAUTH_2) {
    return AuthOAuth2;
  }
  return AuthNone;
}

static getS3Key(publicUrl: string): string {
  if (!publicUrl) {
    throw new TypeError('key is required');
  }

  const exec = new RegExp(
    `(?<=https://s3.${process.env.AWS_S3_BUCKET_NAME_REGION}.amazonaws.com/${process.env.AWS_S3_BUCKET_NAME}/).*`,
  ).exec(publicUrl);

  if (!exec) {
    throw new TypeError('publicUrl is invalid');
  }

  return exec[0];
}

export function extend(obj1: unknown, obj2: unknown) {
  if (isString(obj1)) {
    return isString(obj2)
      ? [defaultTo(obj1, ''), defaultTo(obj2, '')]
      : [defaultTo(obj1, '')].concat(defaultTo(obj2, []));
  }
  if (isArray(obj1)) {
    return defaultTo(obj1, []).concat(defaultTo(obj2, []));
  }
  return {
    ...((obj1 as object) || {}),
    ...((obj2 as object) || {}),
  };
}

@MessagePattern('math.sum.sync.string')
  mathSumSyncString(data: any) {
    // this.logger.error(util.format('mathSumSyncString() data: %o', data));
    return (data.value.split(',') || [])
      .map(i => {
        return parseFloat(i);
      })
      .reduce((a, b) => a + b);
  }

@MessagePattern('math.sum.sync.number')
  mathSumSyncNumber(data: any) {
    // this.logger.error(util.format('mathSumSyncNumber() data: %o', data));
    return (data.value.toString().split('') || [])
      .map(i => {
        return parseFloat(i);
      })
      .reduce((a, b) => a + b);
  }

@Sse('sse/burst')
  sseBurst(
    @Query('n') n = '20',
    @Query('size') size = '65536',
  ): Observable<MessageEvent> {
    const count = parseInt(n, 10);
    const payload = 'X'.repeat(parseInt(size, 10));

    return new Observable(subscriber => {
      for (let i = 0; i < count; i++) {
        subscriber.next({ data: payload });
      }
      subscriber.complete();
    });
  }

function fmtBytesPerSec(n: number): string {
  if (!Number.isFinite(n)) return 'n/a';
  const abs = Math.abs(n);
  if (abs >= 1024 ** 3) return `${(n / 1024 ** 3).toFixed(2)} GB/s`;
  if (abs >= 1024 ** 2) return `${(n / 1024 ** 2).toFixed(2)} MB/s`;
  if (abs >= 1024) return `${(n / 1024).toFixed(2)} KB/s`;
  return `${n.toFixed(0)} B/s`;
}

writeMessage(
  message: MessageEvent,
  cb: (error: Error | null | undefined) => void,
) {
  if (message.id === undefined || message.id === null) {
    this.lastEventId!++;
    message.id = this.lastEventId!.toString();
  }

  if (!this.write(message, 'utf-8')) {
    this.once('drain', cb);
  } else {
    process.nextTick(cb);
  }
}

constructor(public readonly socket: Socket) {
  this.socket.on('data', this.onData.bind(this));
  this.socket.on(TcpEventsMap.CONNECT, () => (this.isClosed = false));
  this.socket.on(TcpEventsMap.CLOSE, () => (this.isClosed = true));
  this.socket.on(TcpEventsMap.ERROR, () => (this.isClosed = true));
}

export function validateUUID(str: string, name: string) {
  const uuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  const uuidV4 = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidV4.test(str) && !uuid.test(str)) {
    throw new RequestQueryException(`Invalid param ${name}. UUID string expected`);
  }
}

(prototype: any): string[] => {
  const result: Set<string> = new Set();
  const iterate = (m: any) => {
    if (m === null) return;
    for (const k of Object.getOwnPropertyNames(m)) result.add(k);
    iterate(Object.getPrototypeOf(m));
  };
  iterate(prototype);
  return Array.from(result);
}

escapeNonVariable = (str: string): string => {
  str = escape(str);
  for (const [before, after] of VARIABLE_REPLACERS)
    str = str.split(before).join(after);
  for (let i: number = 0; i <= 9; ++i)
    if (str[0] === i.toString()) {
      str = "_" + str;
      break;
    }
  if (str === "") return "_empty_";
  return str;
}

shrink = (routeList: Array<ITypedHttpRoute | ITypedWebSocketRoute>) => {
  const dict: Map<string, number> = prepare(routeList);
  for (const route of routeList) {
    if (
      route.accessor.length < 2 ||
      route.accessor.at(-1) !== route.accessor.at(-2)
    )
      continue;

    const cut: string[] = route.accessor.slice(0, -1);
    if ((dict.get(cut.join(".")) ?? 0) > 1) continue;

    route.accessor = cut;
  }
}

private async cleanScopesForGroup(
  groupId: number,
  scopes: InputJsonValue,
): Promise<JsonValue[]> {
  if (!Array.isArray(scopes)) return [];
  return (scopes as string[]).filter((i) =>
    Object.keys(
      Object.keys(groupOwnerScopes).map((i) =>
        i.replace('{groupId}', groupId.toString()),
      ),
    ).includes(i),
  );
}

